mapper.select:
SELECT CATEGORY_NO, CATEGORY_NAME, GAME_CODE FROM CATEGORY_TABLE
WHERE GAME_CODE = #{gameCode}
ORDER BY CATEGORY_NO ASC

SELECT * FROM ( SELECT ROWNUM AS RNUM , T1.* FROM ( SELECT B.BOARD_NO, B.BOARD_TITLE , U.USER_NAME , B.READ_COUNT AS count, B.POST_DATE AS postDate, C.GAME_CODE, C.CATEGORY_NAME FROM BOARD B LEFT JOIN LOG_GG_USER U ON B.USER_NO = U.USER_NO JOIN CATEGORY_TABLE C ON B.CATEGORY_NO = C.CATEGORY_NO WHERE BOARD_CD = 'Y' AND C.GAME_CODE = #{gameCode}
AND B.CATEGORY_NO = #{categoryNo}
ORDER BY B.BOARD_NO DESC) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT COUNT(*)
FROM BOARD B
LEFT JOIN LOG_GG_USER U ON B.USER_NO = U.USER_NO
WHERE BOARD_CD = 'Y'
	AND B.GAME_CODE = #{gameCode}

 	 AND B.CATEGORY_NO = #{categoryNo}

mapper.insert:
INSERT INTO PARTY_RECRUIT (
	BOARD_NO, 
	CAPACITY, 
	TIER, 
	CURRENT, 
	PREFER_MAP
) VALUES (
	#{boardNo}, #{capacity}, #{tier}, #{current}, #{preferMap}
)

INSERT INTO ATTACH_FILE (
FILE_NO, BOARD_NO, ORIGIN_NAME, CHANGE_NAME, FILE_PATH, FILE_EXT, FILE_SIZE
) VALUES (
SEQ_FILE_NO.NEXTVAL, #{boardNo}, #{originName}, #{changeName}, 
#{filePath}, #{fileExt},#{fileSize}
)

INSERT INTO ATTACH_FILE (
FILE_NO, BOARD_NO, ORIGIN_NAME, CHANGE_NAME, FILE_PATH, FILE_EXT, FILE_SIZE
)
SELECT SEQ_FILE_NO.NEXTVAL, A.* FROM (

	SELECT
	#{f.boardNo}, #{f.originName}, #{f.changeName},
	#{f.filePath}, #{f.fileExt}, #{f.fileSize}
	FROM DUAL

) A

INSERT INTO REPLY (
REPLY_NO, USER_NO, BOARD_NO, USER_NAME, REPLY_CONTENT
) VALUES (
SEQ_REPLY_NO.NEXTVAL, #{userNo}, #{boardNo}, #{userName}, #{replyContent}
)

mapper.update:
UPDATE BOARD
SET 
	BOARD_TITLE = #{boardTitle},
	BOARD_CONTENT = #{boardContent}
WHERE BOARD_NO = #{boardNo}

UPDATE ATTACH_FILE
SET 
	ORIGIN_NAME = #{originName},
	CHANGE_NAME = #{changeName},
	FILE_PATH = #{filePath}
WHERE FILE_NO = #{fileNo}
